const pick = (...vals) => {
  for (const v of vals) {
    if (v !== undefined && v !== null && String(v).trim() !== '') return String(v).trim();
  }
  return '';
};

const cap = (s = '') => s ? s.charAt(0).toUpperCase() + s.slice(1).toLowerCase() : '';

const email = pick($json['Email'], $json['E-mail'], $json.email, $json.mail);
let firstName = pick($json['First Name'], $json.first_name, $json.firstName, $json['Imię'], $json['Imie']);
let lastName = pick($json['Last Name'], $json.last_name, $json.lastName, $json['Nazwisko']);
const rawName = pick($json.name, $json.Name, $json['Full Name'], $json.full_name, $json.fullName);

const domain = (email.split('@')[1] || '').toLowerCase();
const domainName = (domain.split('.')[0] || '').toLowerCase();

const personalDomains = [
  'gmail', 'googlemail', 'outlook', 'hotmail', 'live', 'msn',
  'yahoo', 'ymail', 'aol', 'icloud', 'me', 'mac',
  'protonmail', 'proton', 'tutanota', 'zoho',
  'wp', 'onet', 'interia', 'o2', 'tlen', 'poczta',
  'mail', 'email', 'inbox'
];
const isPersonal = personalDomains.includes(domainName);

// 1) fallback z pola name
if ((!firstName || !lastName) && rawName) {
  const parts = rawName.split(/\s+/).filter(Boolean);
  if (!firstName) firstName = parts[0] || '';
  if (!lastName) lastName = parts.length > 1 ? parts[parts.length - 1] : '';
}

// 2) fallback z emaila (np. jan.horubala@gmail.com -> Jan Horubala)
const emailUser = (email.split('@')[0] || '').toLowerCase();
const emailParts = emailUser.split(/[._-]+/).filter(Boolean);
const emailFirst = emailParts[0] || '';
const emailLast = emailParts[1] || '';

if (!firstName && emailFirst) firstName = cap(emailFirst);
if (!lastName && emailLast) lastName = cap(emailLast);

const fullName = (rawName || `${firstName} ${lastName}`).trim();

// alternatywna nazwa z emaila (pomaga przy literówkach w imieniu)
let altName = '';
if (emailFirst) {
  const altLast = emailLast || (!isPersonal && domainName.length >= 4 ? domainName : '');
  altName = `${cap(emailFirst)} ${cap(altLast)}`.trim();
}

let query = 'site:linkedin.com/in';
if (fullName && altName && fullName.toLowerCase() !== altName.toLowerCase()) {
  query += ` ("${fullName}" OR "${altName}")`;
} else if (fullName) {
  query += ` (${fullName} OR "${fullName}")`;
} else if (altName) {
  query += ` (${altName} OR "${altName}")`;
}

if (!isPersonal && domainName) query += ` ${domainName}`;

return {
  email,
  first_name: firstName,
  last_name: lastName,
  full_name: fullName,
  domain,
  company_hint: isPersonal ? '' : domainName,
  is_business_email: !isPersonal,
  search_query: query
};

