const orig = $('Prepare your search').item.json;
const search = $('Choose the best match').item.json;

function uniq(arr) {
  return [...new Set((arr || []).filter(v => !!v))];
}

function toDateText(d) {
  if (!d) return '';
  if (typeof d === 'string') return d.trim();
  if (typeof d === 'object') {
    if (d.text) return String(d.text).trim();
    const year = d.year || d.y;
    const month = d.month || d.m;
    if (month && year) return month + ' ' + year;
    if (year) return String(year);
  }
  return '';
}

function isCurrentJob(job) {
  if (!job || typeof job !== 'object') return false;
  if (job.isCurrent === true || job.is_current === true) return true;

  const end = job.endDate || job.end_date || job.endsAt || job.ends_at || job.to;
  if (!end) return true;

  if (typeof end === 'string') {
    return /present|obecnie|now/i.test(end);
  }

  if (typeof end === 'object') {
    const t = String(end.text || '').toLowerCase();
    if (t.includes('present') || t.includes('obecnie') || t.includes('now')) return true;
    if (!end.year && !end.month && !end.text) return true;
  }

  return false;
}

function skillList(raw) {
  if (Array.isArray(raw.topSkills)) return raw.topSkills.join(', ');
  if (typeof raw.topSkills === 'string') return raw.topSkills;

  if (Array.isArray(raw.skills)) {
    return raw.skills
      .map(s => (typeof s === 'string' ? s : (s && (s.name || s.skill)) || ''))
      .filter(Boolean)
      .slice(0, 12)
      .join(', ');
  }
  return '';
}

function shortText(v, max = 500) {
  const s = String(v || '').trim();
  if (!s) return '';
  return s.length > max ? s.slice(0, max) + '...' : s;
}

if ($json.error) {
  return {
    email: orig.email,
    first_name: orig.first_name,
    last_name: orig.last_name,
    linkedin_url: search.linkedin_url || '',
    kraj: '',
    rola: '',
    firma: '',
    link_do_firmy: '',
    kiedy_zaczeto_firme: '',
    informacje: '',
    source: 'serper_fallback',
    enrichment_status: 'partial',
    error_detail: ($json.error || '') + ' (statusCode: ' + ($json.statusCode || '') + ')',
    enrichment_date: new Date().toISOString()
  };
}

const raw = Array.isArray($json) ? ($json[0] || {}) : ($json || {});

if (!raw || Object.keys(raw).length === 0) {
  return {
    email: orig.email,
    first_name: orig.first_name,
    last_name: orig.last_name,
    linkedin_url: search.linkedin_url || '',
    kraj: '',
    rola: '',
    firma: '',
    link_do_firmy: '',
    kiedy_zaczeto_firme: '',
    informacje: '',
    source: 'serper_fallback',
    enrichment_status: 'partial',
    error_detail: 'empty_apify_response',
    enrichment_date: new Date().toISOString()
  };
}

const jobs = Array.isArray(raw.experience) ? raw.experience : (Array.isArray(raw.experiences) ? raw.experiences : []);
const currentJobs = jobs.filter(isCurrentJob);

const roles = uniq(currentJobs.map(j => j.position || j.title || j.jobTitle || j.job_title || ''));
const companies = uniq(currentJobs.map(j => j.companyName || j.company || j.organization || ''));
const companyLinks = uniq(currentJobs.map(j => j.companyLinkedinUrl || j.companyUrl || j.companyProfileUrl || j.companyWebsite || ''));
const companyStarts = uniq(currentJobs.map(j => {
  const company = j.companyName || j.company || '';
  const start = toDateText(j.startDate || j.start_date || j.startedAt || j.startsAt);
  if (company && start) return company + ': ' + start;
  return start || '';
}));

const location = raw.location || {};
const country =
  (location.parsed && (location.parsed.countryFull || location.parsed.country)) ||
  location.country ||
  raw.country ||
  '';

const headline = raw.headline || raw.occupation || raw.title || '';
const topSkills = skillList(raw);
const about = raw.about || raw.summary || raw.bio || '';

const informacje =
  'headline: ' + (headline || '-') +
  '; top skills: ' + (topSkills || '-') +
  '; about: ' + (shortText(about) || '-');

const hasData = !!(country || roles.length || companies.length || headline || topSkills || about);

return {
  email: orig.email,
  first_name: orig.first_name,
  last_name: orig.last_name,
  linkedin_url: search.linkedin_url || raw.linkedinUrl || raw.profileUrl || '',
  kraj: country,
  rola: roles.join(' | '),
  firma: companies.join(' | '),
  link_do_firmy: companyLinks.join(' | '),
  kiedy_zaczeto_firme: companyStarts.join(' | '),
  informacje,
  source: hasData ? 'apify_profile' : 'serper_fallback',
  enrichment_status: hasData ? 'success' : 'partial',
  error_detail: hasData ? '' : 'apify_missing_current_data',
  enrichment_date: new Date().toISOString()
};

