if ($json.error) {
  return {
    matched: false,
    linkedin_url: '',
    error: ($json.error || '') + ' (statusCode: ' + ($json.statusCode || '') + ')'
  };
}

const orig = $('Prepare your search').item.json;
const firstName = (orig.first_name || '').toLowerCase();
const lastName = (orig.last_name || '').toLowerCase();
const companyHint = (orig.company_hint || '').toLowerCase();

const items = ($json.organic || []).map(r => ({
  link: r.link || '',
  title: r.title || '',
  snippet: r.snippet || ''
}));

if (items.length === 0) {
  return { matched: false, linkedin_url: '', search_title: '', search_snippet: '' };
}

let bestMatch = null;
let bestScore = -1;

for (const item of items) {
  if (!item.link || !item.link.includes('linkedin.com/in/')) continue;

  let score = 0;
  const title = item.title.toLowerCase();
  const snippet = item.snippet.toLowerCase();

  if (firstName && title.includes(firstName)) score += 3;
  if (lastName && title.includes(lastName)) score += 3;
  if (companyHint && title.includes(companyHint)) score += 5;
  if (companyHint && snippet.includes(companyHint)) score += 2;

  if (score > bestScore) {
    bestScore = score;
    bestMatch = item;
  }
}

if (!bestMatch || bestScore < 3) {
  return { matched: false, linkedin_url: '', search_title: '', search_snippet: '' };
}

return {
  matched: true,
  linkedin_url: bestMatch.link || '',
  search_title: bestMatch.title || '',
  search_snippet: (bestMatch.snippet || '').substring(0, 200),
  match_score: bestScore
};
